  payload = '{"species": "Quinoa", "species_slug": "quinoa", "varieties": [{"name": "White Quinoa (Generic Commercial)", "slug": "white-quinoa-generic-commercial", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 0, "origin": "Andean highlands, mixed sources", "traits": "Cream to golden seeds, 1.5-2mm diameter, light fluffy texture when cooked", "flesh_fruit": "Mild, nutty flavor; soft texture; versatile in cooking", "yield_notes": "Low to moderate in humid subtropical climates (500-1000 kg/ha estimated)", "growing_notes": "Most commonly available in Australia. Winter planting (April-June) only. Requires night temps below 20°C for germination. Sensitive to humid subtropical climates summer heat (>32°C) and humidity. High risk of fungal diseases in humid conditions. Saponin layer helps protect against pests but requires thorough washing.", "availability": "The Seed Vine (humid subtropical climates area), Boondie Seeds, Australian Wheatgrass (organic), Lost Seed"}, {"name": "Red Quinoa", "slug": "red-quinoa", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 1, "origin": "Andean highlands, Peru/Bolivia", "traits": "Red-brown seeds, retains shape well, slightly chewy texture, colorful", "flesh_fruit": "Nutty, earthy, robust flavor; firm texture maintains in salads", "yield_notes": "Low to moderate (similar to white quinoa in humid subtropical climates)", "growing_notes": "Marginally better heat tolerance than white. Best for autumn planting (March-May). Seed coat thickness helps resist humidity-related degradation. Still struggles above 30°C. Good for humid subtropical climates winter but avoid flowering during hot spells.", "availability": "Royal Nut Company (organic), specialty seed suppliers"}, {"name": "Black Quinoa", "slug": "black-quinoa", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 2, "origin": "Andean highlands", "traits": "Black to deep purple seeds, smallest size, crunchiest texture, high fiber", "flesh_fruit": "Earthy, slightly sweet; firmest texture of all quinoas", "yield_notes": "Lower than other colors (500-800 kg/ha estimated)", "growing_notes": "Longest maturity time (110-130 days). Most heat-tolerant of the three colors but still challenged by humid subtropical climates climate. Slower germination. Best autumn planting. Thick seed coat somewhat protects against humidity.", "availability": "Limited; occasionally from specialty Australian seed companies"}, {"name": "Rainbow/Tri-Color Quinoa", "slug": "rainbow-tri-color-quinoa", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 3, "origin": "Mixed Andean sources", "traits": "Blend of white, red, and black seeds; visually appealing mix", "flesh_fruit": "Varied flavors and textures in one dish", "yield_notes": "Variable depending on color proportions", "growing_notes": "Popular consumer product. humid subtropical climates challenges same as individual colors. Winter growing only. Provides genetic diversity which may help with adaptation.", "availability": "Australian health food suppliers, some seed companies"}, {"name": "BEW / Kruso White", "slug": "bew-kruso-white", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 4, "origin": "Selected in Kununurra, Western Australia; released 2019", "traits": "White seeds, compact seed heads, late maturing, Australian-adapted", "flesh_fruit": "Good quality white grain", "yield_notes": "Up to 2-3 t/ha in ideal irrigated tropical conditions (Kununurra)", "growing_notes": "", "availability": ""}, {"name": "Titicaca", "slug": "titicaca", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 5, "origin": "Denmark/Europe-bred from Bolivian germplasm", "traits": "White seeds, early maturity (90-110 days), uniform, photoperiod-insensitive", "flesh_fruit": "High-quality white grain, fluffy when cooked", "yield_notes": "2-3 t/ha in temperate