: "", "availability": ""}, {"name": "Royal Quinoa (Quinoa Real)", "slug": "royal-quinoa-quinoa-real", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 9, "origin": "Southern Bolivian Altiplano (salt flats, 12,000 ft elevation)", "traits": "Largest seeds (2-3mm), pearly white, premium quality, 50+ local varieties", "flesh_fruit": "Nutty, fluffy, superior flavor and texture", "yield_notes": "High in native habitat (3-5 t/ha)", "growing_notes": "Most prized quinoa globally. Grows ONLY in extreme high-altitude Bolivian salt deserts. Requires freezing nights, hot days, low humidity, saline soil. Completely incompatible with humid subtropical climates or tropical monsoon climates. \"Champagne of Quinoa\".", "availability": "Imported grain available; seed cultivation impossible outside Altiplano"}, {"name": "Pasankalla (INIA 415)", "slug": "pasankalla-inia-415", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 10, "origin": "Altiplano, Peru/Bolivia (3000+ years old)", "traits": "Dark red-brown to purple seeds, traditional Andean variety, high protein (14%+)", "flesh_fruit": "Nutty, rich flavor; used in traditional Andean dishes", "yield_notes": "Moderate to high in Andes", "growing_notes": "Ancient heirloom. Sacred to Andean cultures. High-altitude adapted (3500-3900m). Heat-sensitive. Cultural significance in Peru. Not viable for low-altitude tropical/subtropical regions.", "availability": "Seed banks; specialty Andean suppliers"}, {"name": "Chullpi", "slug": "chullpi", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 11, "origin": "High Andean plateaus (3900m+)", "traits": "Translucent white seeds, sweet milky flavor when fresh, rare variety", "flesh_fruit": "Uniquely sweet, delicate; prized for traditional Andean soups", "yield_notes": "Low; specialty crop", "growing_notes": "Rare heirloom variety at risk of extinction. Cold-hardy, requires high altitude. Sweet flavor without bitterness. Cultural importance in traditional Andean cuisine. Not viable outside high-altitude cool climates.", "availability": "Extremely limited; Andean seed conservation programs"}, {"name": "Kancolla (Blanca de Juli)", "slug": "kancolla-blanca-de-juli", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 12, "origin": "Lake Titicaca region, Peru", "traits": "White seeds, traditional lakeside variety", "flesh_fruit": "Good quality grain", "yield_notes": "Moderate", "growing_notes": "Traditional variety from favorable Titicaca microclimate. Requires cool temperatures, moderate moisture. High-altitude crop. Not adapted to tropical lowlands.", "availability": "Peruvian seed banks"}, {"name": "Salcedo INIA", "slug": "salcedo-inia", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 13, "origin": "Peru (INIA breeding program), released 1990", "traits": "White seeds, improved variety, low saponin, disease resistant", "flesh_fruit": "Excellent grain quality, mild flavor", "yield_notes": "High in Andean conditions (3-4 t/ha)", "growing_notes": "One of Peru''s most successful improved varieties. Bred for Altiplano (3800-3900m elevation). Tolerates frost and drought of high Andes. NOT heat-tolerant. Unsuitable for tropical lowlands.", "availability": "INIA Peru; international research institutions"}, {"name": "Negra Collana (INIA 420)", "slug": "negra-collana-inia-420", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 14, "origin": "Puno, Peru (high Andes)", "traits": "Black seeds, traditional variety, high antioxidants", "flesh_fruit": "Earthy, distinctive flavor", "yield_notes": "Moderate", "growing_notes": "Traditional black quinoa variety. High nutritional value, rich in anthocyanins. High-altitude adapted. Long growing cycle (120+ days). Not suitable for tropical climates.", "availability": "Peruvian seed conservation"}, {"name": "Kaslala Multicolor", "slug": "kaslala-multicolor", "lineage_